import Foundation

nonisolated enum Lang {
    static var current: String {
        UserDefaults.standard.string(forKey: "appLanguage") ?? "en"
    }

    static func s(_ key: String) -> String {
        translations[key]?[current] ?? translations[key]?["en"] ?? key
    }

    static func localizedDayName(_ englishDay: String) -> String {
        let key = englishDay.lowercased()
        return translations[key]?[current] ?? englishDay
    }

    static func localizedGoal(_ goalRaw: String) -> String {
        switch goalRaw {
        case "Lose Weight": return s("goal_lose_weight")
        case "Maintain Weight": return s("wg_maintain")
        case "Gain Muscle": return s("goal_gain_muscle")
        default: return goalRaw
        }
    }

